import { SubscribeRequest, SubscriptionResponse} from '@/src/entities'

export default class SubscriptionClient {
    async getSubscriptions(): Promise<SubscriptionResponse[]> {
        const response = await fetch(`/subscriptions`, {
            method: "GET",
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`Get subscriptions failed with code: ${response.status}`)
        const result: SubscriptionResponse[] = await response.json()
        return result
    }

    async subscribe (subscribeRequest: SubscribeRequest): Promise<boolean> {
        const response = await fetch(`/subscribe`, {
            method: "POST",
            body: JSON.stringify({
                subscription_id: subscribeRequest.subscription_id,
                limit: subscribeRequest.limit,
                price: subscribeRequest.price
            }),
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`Subscribe failed with code: ${response.status}`)
        return response.ok
    }
}