import { UrlResponse, AnalyticsResponse } from '@/src/entities'

export default class DataClient {
    async getUrlList(): Promise<UrlResponse[]> {
        const response = await fetch(`/urls`, {
            method: "GET",
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error('Failed to fetch URL list')
        const result: UrlResponse[] = await response.json()
        return result
    }

    async getAnalytics(url_id: number): Promise<AnalyticsResponse> {

        const response = await fetch(`/analytics?url_id=${url_id}`, {
            method: "GET",
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error("Get analytics failed with HTTP status")
        const result: AnalyticsResponse = await response.json()
        return result
    }
}
